```typescript
interface UseAudioCaptureReturn {
  isCapturing: boolean;
  isSpeaking: boolean;        // NEW — true while VAD detects speech
  audioSource: AudioSource | null;
  startMicrophone: () => Promise<void>;
  startTabCapture: () => Promise<void>;
  stop: () => void;
  error: string | null;
}
```

