generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

// ═══════════════════════════════════════
// Multi-tenant
// ═══════════════════════════════════════

model Organization {
  id        String   @id @default(cuid())
  name      String
  plan      Plan     @default(FREE)
  createdAt DateTime @default(now())
  users     User[]
  interviews Interview[]
}

enum Plan {
  FREE
  PRO
  ENTERPRISE
}

model User {
  id        String   @id @default(cuid())
  email     String   @unique
  name      String
  password  String   // bcrypt hash
  role      Role     @default(RECRUITER)
  orgId     String
  org       Organization @relation(fields: [orgId], references: [id])
  interviews Interview[]
  createdAt DateTime @default(now())
}

enum Role {
  ADMIN
  RECRUITER
}

// ═══════════════════════════════════════
// Entretiens
// ═══════════════════════════════════════

model Interview {
  id             String    @id @default(cuid())
  title          String
  candidateName  String
  candidateEmail String?
  status         InterviewStatus @default(PREP)
  language       String    @default("fr")
  jobDescription String?   @db.Text
  techStack      String?
  cvContent      String?   @db.Text

  orgId     String
  org       Organization @relation(fields: [orgId], references: [id])
  userId    String
  user      User @relation(fields: [userId], references: [id])

  scorecard   Scorecard?
  questions   Question[]
  transcript  TranscriptEntry[]
  summary     InterviewSummary?

  scheduledAt DateTime?
  startedAt   DateTime?
  endedAt     DateTime?
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([orgId])
  @@index([userId])
}

enum InterviewStatus {
  PREP
  READY
  LIVE
  REVIEW
  COMPLETED
  ARCHIVED
}

// ═══════════════════════════════════════
// Questions
// ═══════════════════════════════════════

model Question {
  id             String   @id @default(cuid())
  text           String
  category       QuestionCategory
  difficulty     Difficulty
  expectedAnswer String?  @db.Text
  order          Int
  isAsked        Boolean  @default(false)

  interviewId  String
  interview    Interview @relation(fields: [interviewId], references: [id], onDelete: Cascade)

  answer       QuestionAnswer?
}

enum QuestionCategory {
  TECHNICAL
  SYSTEM_DESIGN
  BEHAVIORAL
  CULTURE_FIT
  PROBLEM_SOLVING
}

enum Difficulty {
  EASY
  MEDIUM
  HARD
}

model QuestionAnswer {
  id         String  @id @default(cuid())
  transcript String  @db.Text
  score      Int?
  notes      String? @db.Text

  questionId String   @unique
  question   Question @relation(fields: [questionId], references: [id], onDelete: Cascade)
}

// ═══════════════════════════════════════
// Scorecard
// ═══════════════════════════════════════

model Scorecard {
  id             String   @id @default(cuid())
  criteria       ScorecardCriterion[]
  overallScore   Int?
  recommendation Recommendation?

  interviewId String    @unique
  interview   Interview @relation(fields: [interviewId], references: [id], onDelete: Cascade)
}

enum Recommendation {
  STRONG_HIRE
  HIRE
  LEAN_HIRE
  LEAN_NO_HIRE
  NO_HIRE
  STRONG_NO_HIRE
}

model ScorecardCriterion {
  id          String   @id @default(cuid())
  name        String
  description String?
  weight      Int      @default(1)
  score       Int?
  notes       String?  @db.Text

  scorecardId String
  scorecard   Scorecard @relation(fields: [scorecardId], references: [id], onDelete: Cascade)
}

// ═══════════════════════════════════════
// Transcription
// ═══════════════════════════════════════

model TranscriptEntry {
  id          String   @id @default(cuid())
  text        String
  speaker     Speaker
  timestamp   DateTime @default(now())
  confidence  Float?

  interviewId String
  interview   Interview @relation(fields: [interviewId], references: [id], onDelete: Cascade)

  @@index([interviewId])
}

enum Speaker {
  INTERVIEWER
  CANDIDATE
}

// ═══════════════════════════════════════
// Résumé post-entretien
// ═══════════════════════════════════════

model InterviewSummary {
  id              String   @id @default(cuid())
  summary         String   @db.Text
  strengths       String[]
  weaknesses      String[]
  redFlags        String[]
  keyTopics       String[]
  followUpActions String[]

  interviewId String    @unique
  interview   Interview @relation(fields: [interviewId], references: [id], onDelete: Cascade)

  createdAt DateTime @default(now())
}

