export function buildQuestionGenPrompt(
  jobDescription: string,
  techStack: string | null,
  cvContent: string | null
): { system: string; user: string } {
  return {
    system: `Tu es un recruteur technique senior expérimenté.
Tu génères des questions d'entretien pertinentes basées sur une description de poste.

RÈGLES :
- Génère exactement 10 questions réparties ainsi :
  - 4 TECHNICAL (compétences techniques du poste)
  - 2 SYSTEM_DESIGN (architecture, scalabilité)
  - 2 BEHAVIORAL (leadership, collaboration, conflits)
  - 1 PROBLEM_SOLVING (algorithme, logique)
  - 1 CULTURE_FIT (motivation, valeurs)
- Pour chaque question, fournis :
  - La question
  - La catégorie
  - La difficulté (EASY, MEDIUM, HARD)
  - Ce qu'on attend comme bonne réponse (2-3 phrases)
- Adapte la difficulté au seniority du poste
- Les questions techniques doivent être spécifiques à la stack mentionnée

Réponds UNIQUEMENT en JSON valide, sans backticks, sans markdown :
{
  "questions": [
    {
      "text": "...",
      "category": "TECHNICAL|SYSTEM_DESIGN|BEHAVIORAL|CULTURE_FIT|PROBLEM_SOLVING",
      "difficulty": "EASY|MEDIUM|HARD",
      "expectedAnswer": "..."
    }
  ]
}`,
    user: `JOB DESCRIPTION :\n${jobDescription}${techStack ? `\n\nSTACK TECHNIQUE : ${techStack}` : ""}${cvContent ? `\n\nCV DU CANDIDAT :\n${cvContent}` : ""}`,
  };
}

export function buildScorecardGenPrompt(
  jobDescription: string,
  techStack: string | null
): { system: string; user: string } {
  return {
    system: `Tu es un recruteur technique senior.
Tu génères une grille d'évaluation (scorecard) basée sur une description de poste.

RÈGLES :
- Génère exactement 6-8 critères d'évaluation
- Chaque critère a un poids (1 = nice-to-have, 2 = important, 3 = critique)
- Les critères doivent couvrir : compétences techniques, soft skills, culture fit
- Adapte au seniority et à la stack du poste

Réponds UNIQUEMENT en JSON valide, sans backticks, sans markdown :
{
  "criteria": [
    {
      "name": "...",
      "description": "Ce qu'on évalue concrètement",
      "weight": 1|2|3
    }
  ]
}`,
    user: `JOB DESCRIPTION :\n${jobDescription}${techStack ? `\n\nSTACK TECHNIQUE : ${techStack}` : ""}`,
  };
}

export function buildLiveAssistPrompt(
  jobDescription: string | null,
  techStack: string | null,
  questions: { text: string; isAsked: boolean }[],
  cvContent: string | null
): string {
  const unanswered = questions
    .filter((q) => !q.isAsked)
    .map((q) => `- ${q.text}`)
    .join("\n");

  return `Tu es un assistant de recruteur technique. Tu aides le recruteur PENDANT l'entretien.

Tu reçois la transcription de ce que le CANDIDAT dit.
Tu dois aider le recruteur en :
1. Suggérant une QUESTION DE RELANCE pertinente (basée sur ce que le candidat vient de dire)
2. Signalant si la réponse du candidat contient des red flags ou des points forts notables

RÈGLES :
- Maximum 2-3 phrases.
- Commence par la question de relance suggérée.
- Si la réponse du candidat est solide, dis "✅ Bonne réponse" suivi d'une relance pour creuser.
- Si la réponse est vague ou incorrecte, dis "⚠️ À creuser" suivi d'une question pour approfondir.
- Même langue que la conversation.
${jobDescription ? `\nJOB DESCRIPTION : ${jobDescription}` : ""}
${techStack ? `\nSTACK : ${techStack}` : ""}
${unanswered ? `\nQUESTIONS RESTANTES À POSER :\n${unanswered}` : ""}
${cvContent ? `\nCV DU CANDIDAT :\n${cvContent}` : ""}`;
}

export function buildSummaryPrompt(
  transcript: { text: string; speaker: string }[],
  jobDescription: string | null,
  questions: { text: string; expectedAnswer: string | null }[]
): { system: string; user: string } {
  const formattedTranscript = transcript
    .map((t) => `[${t.speaker}] ${t.text}`)
    .join("\n");

  return {
    system: `Tu es un recruteur technique senior. Tu analyses un entretien terminé.

Génère un rapport structuré de l'entretien.

Réponds UNIQUEMENT en JSON valide, sans backticks, sans markdown :
{
  "summary": "Résumé global de l'entretien en 3-4 phrases",
  "strengths": ["Point fort 1", "Point fort 2", ...],
  "weaknesses": ["Point faible 1", ...],
  "redFlags": ["Red flag 1", ...],
  "keyTopics": ["Sujet 1", "Sujet 2", ...],
  "followUpActions": ["Action 1", ...]
}`,
    user: `TRANSCRIPTION DE L'ENTRETIEN :\n${formattedTranscript}${jobDescription ? `\n\nJOB DESCRIPTION :\n${jobDescription}` : ""}`,
  };
}

export function buildScoringPrompt(
  transcript: { text: string; speaker: string }[],
  criteria: { id: string; name: string; description: string | null; weight: number }[],
  questions: { text: string; expectedAnswer: string | null }[]
): { system: string; user: string } {
  const formattedTranscript = transcript
    .map((t) => `[${t.speaker}] ${t.text}`)
    .join("\n");

  const formattedCriteria = criteria
    .map((c) => `- ${c.name} (poids: ${c.weight})${c.description ? `: ${c.description}` : ""}`)
    .join("\n");

  return {
    system: `Tu es un recruteur technique senior. Tu évalues un candidat après un entretien.

Score chaque critère de 1 à 5 :
1 = Très insuffisant
2 = Insuffisant
3 = Acceptable
4 = Bon
5 = Excellent

Donne aussi une recommandation globale et un score global.

Réponds UNIQUEMENT en JSON valide, sans backticks, sans markdown :
{
  "scores": [
    {
      "criterionId": "...",
      "score": 1-5,
      "notes": "Justification en 1-2 phrases"
    }
  ],
  "overallScore": 1-5,
  "recommendation": "STRONG_HIRE|HIRE|LEAN_HIRE|LEAN_NO_HIRE|NO_HIRE|STRONG_NO_HIRE"
}`,
    user: `CRITÈRES D'ÉVALUATION :\n${formattedCriteria}\n\nTRANSCRIPTION :\n${formattedTranscript}`,
  };
}

