      }),
    login: (body: { email: string; password: string }) =>
      request<{ token: string; user: AuthUser }>("/auth/login", {
        method: "POST",
        body: JSON.stringify(body),
      }),
    me: () => request<AuthUser>("/auth/me"),
  },

  interviews: {
    list: () => request<InterviewListItem[]>("/interviews"),
    create: (body: CreateInterviewRequest) =>
      request<InterviewDetail>("/interviews", { method: "POST", body: JSON.stringify(body) }),
    get: (id: string) => request<InterviewDetail>(`/interviews/${id}`),
    update: (id: string, body: Partial<CreateInterviewRequest>) =>
      request<InterviewDetail>(`/interviews/${id}`, { method: "PUT", body: JSON.stringify(body) }),
    delete: (id: string) => request<void>(`/interviews/${id}`, { method: "DELETE" }),
