      }),
  },
};

import { useCallback, useEffect, useState } from "react";
import { api, type AuthUser } from "../lib/api-client";
import { clearToken, setToken } from "../lib/auth";

interface UseAuthReturn {
  user: AuthUser | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  login: (email: string, password: string) => Promise<void>;
  signup: (email: string, password: string, name: string, orgName: string) => Promise<void>;
  logout: () => void;
}

export function useAuth(): UseAuthReturn {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    api.auth.me()
      .then(setUser)
      .catch(() => setUser(null))
      .finally(() => setIsLoading(false));
  }, []);

  const login = useCallback(async (email: string, password: string) => {
    const { token, user } = await api.auth.login({ email, password });
    setToken(token);
    setUser(user);
  }, []);

  const signup = useCallback(async (email: string, password: string, name: string, orgName: string) => {
    const { token, user } = await api.auth.signup({ email, password, name, orgName });
    setToken(token);
    setUser(user);
  }, []);

  const logout = useCallback(() => {
    clearToken();
    setUser(null);
  }, []);

  return { user, isLoading, isAuthenticated: user !== null, login, signup, logout };
}

import { useCallback, useEffect, useRef, useState } from "react";
import type { ClientMessage, ServerMessage } from "@voxhelp/shared";
import { WS_PING_INTERVAL_MS } from "@voxhelp/shared";
import { getToken } from "../lib/auth";

export type ConnectionStatus = "disconnected" | "connecting" | "connected" | "error";

export interface TranscriptEntry {
  id: string;
  text: string;
  speaker?: string;
  timestamp: number;
  isFinal: boolean;
}

export interface Suggestion {
  id: string;
  text: string;
  isStreaming: boolean;
  timestamp: number;
}

interface UseWebSocketReturn {
  status: ConnectionStatus;
  transcripts: TranscriptEntry[];
  currentPartial: string;
  suggestion: Suggestion | null;
  startSession: (interviewId: string) => void;
  stopSession: () => void;
  sendAudio: (base64: string) => void;
  markAsked: (questionId: string) => void;
  requestFollowup: () => void;
  sendQuestion: (question: string) => void;
}

let entryCounter = 0;
function newId() {
  return `${Date.now()}-${++entryCounter}`;
}

export function useWebSocket(url: string): UseWebSocketReturn {
  const wsRef = useRef<WebSocket | null>(null);
  const pingRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const [status, setStatus] = useState<ConnectionStatus>("disconnected");
  const [transcripts, setTranscripts] = useState<TranscriptEntry[]>([]);
  const [currentPartial, setCurrentPartial] = useState("");
  const [suggestion, setSuggestion] = useState<Suggestion | null>(null);

  const send = useCallback((msg: ClientMessage) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(msg));
    }
  }, []);

  const handleMessage = useCallback((msg: ServerMessage) => {
    switch (msg.type) {
      case "transcript:partial":
        setCurrentPartial(msg.text);
        break;
      case "transcript:final":
        setCurrentPartial("");
        setTranscripts((prev) => [
          ...prev,
          { id: newId(), text: msg.text, speaker: msg.speaker, timestamp: Date.now(), isFinal: true },
        ]);
        break;
      case "suggestion:start":
        setSuggestion({ id: newId(), text: "", isStreaming: true, timestamp: Date.now() });
        break;
      case "suggestion:chunk":
        setSuggestion((prev) => prev ? { ...prev, text: prev.text + msg.text } : null);
        break;
      case "suggestion:done":
        setSuggestion((prev) => prev ? { ...prev, text: msg.fullText, isStreaming: false } : null);
        break;
      case "suggestion:error":
        setSuggestion(null);
        break;
    }
  }, []);

  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) return;
    setStatus("connecting");
    const token = getToken();
    const wsUrl = token ? `${url}?token=${token}` : url;
    const ws = new WebSocket(wsUrl);
    wsRef.current = ws;

    ws.onopen = () => {
      setStatus("connected");
      pingRef.current = setInterval(() => send({ type: "ping" }), WS_PING_INTERVAL_MS);
    };
    ws.onmessage = (e) => {
      try { handleMessage(JSON.parse(e.data)); } catch { /* ignore */ }
    };
    ws.onclose = () => {
      setStatus("disconnected");
      if (pingRef.current) { clearInterval(pingRef.current); pingRef.current = null; }
    };
    ws.onerror = () => setStatus("error");
  }, [url, send, handleMessage]);

  const startSession = useCallback((interviewId: string) => {
    setTranscripts([]);
    setSuggestion(null);
    setCurrentPartial("");

    const doStart = () => send({ type: "session:start", interviewId, contextType: "RECRUIT" });

    if (wsRef.current?.readyState === WebSocket.OPEN) {
      doStart();
    } else {
      connect();
      const check = setInterval(() => {
        if (wsRef.current?.readyState === WebSocket.OPEN) {
          clearInterval(check);
          doStart();
        }
      }, 100);
    }
  }, [connect, send]);

  const stopSession = useCallback(() => send({ type: "session:stop" }), [send]);
  const sendAudio = useCallback((base64: string) => send({ type: "audio:chunk", data: base64 }), [send]);
  const markAsked = useCallback((questionId: string) => send({ type: "user:mark-asked", questionId }), [send]);
  const requestFollowup = useCallback(() => send({ type: "user:followup" }), [send]);
  const sendQuestion = useCallback((question: string) => send({ type: "user:question", question }), [send]);

  useEffect(() => {
    connect();
    return () => {
      if (pingRef.current) clearInterval(pingRef.current);
      wsRef.current?.close();
    };
  }, [connect]);

  return { status, transcripts, currentPartial, suggestion, startSession, stopSession, sendAudio, markAsked, requestFollowup, sendQuestion };
}

import { createContext, useContext } from "react";
import { BrowserRouter, Navigate, Route, Routes } from "react-router-dom";
import { useAuth, type AuthUser } from "./hooks/useAuth";
import { Login } from "./pages/Login";
import { Dashboard } from "./pages/Dashboard";
import { InterviewPrep } from "./pages/InterviewPrep";
import { InterviewLive } from "./pages/InterviewLive";
import { InterviewReview } from "./pages/InterviewReview";

interface AuthContextValue {
  user: AuthUser | null;
  logout: () => void;
}

export const AuthContext = createContext<AuthContextValue>({ user: null, logout: () => {} });
export const useAuthContext = () => useContext(AuthContext);

function ProtectedRoute({ children }: { children: React.ReactNode }) {
  const { user, isLoading } = useAuth();
  if (isLoading) return <div className="min-h-screen bg-surface-0 flex items-center justify-center text-white/50">Chargement…</div>;
  if (!user) return <Navigate to="/login" replace />;
  return <>{children}</>;
}

export default function App() {
  const auth = useAuth();

  if (auth.isLoading) {
    return <div className="min-h-screen bg-surface-0 flex items-center justify-center text-white/50">Chargement…</div>;
  }

  return (
    <AuthContext.Provider value={{ user: auth.user, logout: auth.logout }}>
      <BrowserRouter>
        <Routes>
          <Route path="/login" element={auth.isAuthenticated ? <Navigate to="/dashboard" replace /> : <Login />} />
          <Route path="/dashboard" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
          <Route path="/interviews/:id/prep" element={<ProtectedRoute><InterviewPrep /></ProtectedRoute>} />
          <Route path="/interviews/:id/live" element={<ProtectedRoute><InterviewLive /></ProtectedRoute>} />
          <Route path="/interviews/:id/review" element={<ProtectedRoute><InterviewReview /></ProtectedRoute>} />
          <Route path="*" element={<Navigate to={auth.isAuthenticated ? "/dashboard" : "/login"} replace />} />
        </Routes>
      </BrowserRouter>
    </AuthContext.Provider>
  );
}

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";

export function Login() {
  const [mode, setMode] = useState<"login" | "signup">("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [orgName, setOrgName] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const { login, signup } = useAuth();
  const navigate = useNavigate();

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      if (mode === "login") {
        await login(email, password);
      } else {
        await signup(email, password, name, orgName);
      }
      navigate("/dashboard");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Erreur");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-surface-0 flex items-center justify-center p-4">
      <div className="w-full max-w-sm">
        <div className="mb-8 text-center">
          <div className="text-2xl font-bold text-white mb-1">VoxHelp Recruit</div>
          <div className="text-white/50 text-sm">
            {mode === "login" ? "Connectez-vous à votre compte" : "Créez votre compte et organisation"}
          </div>
        </div>

        <form onSubmit={handleSubmit} className="bg-surface-1 rounded-xl p-6 space-y-4 border border-surface-3">
          {mode === "signup" && (
            <>
              <Field label="Votre nom" value={name} onChange={setName} placeholder="Jean Dupont" />
              <Field label="Organisation" value={orgName} onChange={setOrgName} placeholder="Acme Corp" />
            </>
          )}
          <Field label="Email" type="email" value={email} onChange={setEmail} placeholder="vous@exemple.com" />
          <Field label="Mot de passe" type="password" value={password} onChange={setPassword} placeholder="••••••••" />

          {error && <div className="text-danger text-sm">{error}</div>}

          <button
            type="submit"
            disabled={loading}
            className="w-full py-2.5 rounded-lg bg-accent hover:bg-accent-dim disabled:opacity-50 text-white font-medium transition-colors"
          >
            {loading ? "…" : mode === "login" ? "Se connecter" : "Créer le compte"}
          </button>
        </form>

        <button
          onClick={() => setMode(mode === "login" ? "signup" : "login")}
          className="mt-4 w-full text-center text-white/40 hover:text-white/70 text-sm transition-colors"
        >
          {mode === "login" ? "Pas de compte ? Créer un compte" : "Déjà un compte ? Se connecter"}
        </button>
      </div>
    </div>
  );
}

function Field({
  label,
  value,
  onChange,
  placeholder,
  type = "text",
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  type?: string;
}) {
  return (
    <div>
      <label className="block text-white/60 text-sm mb-1">{label}</label>
      <input
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        required
        className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm"
      />
    </div>
  );
}

import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { api } from "../lib/api-client";
import type { InterviewListItem } from "@voxhelp/shared";
import { useAuthContext } from "../App";

const STATUS_LABEL: Record<string, string> = {
  PREP: "Préparation", READY: "Prêt", LIVE: "En cours",
  REVIEW: "À revoir", COMPLETED: "Complété", ARCHIVED: "Archivé",
};
const STATUS_COLOR: Record<string, string> = {
  PREP: "bg-surface-3 text-white/60", READY: "bg-accent/20 text-accent-light",
  LIVE: "bg-danger/20 text-danger", REVIEW: "bg-warning/20 text-warning",
  COMPLETED: "bg-success/20 text-success", ARCHIVED: "bg-surface-3 text-white/30",
};
const RECO_COLOR: Record<string, string> = {
  STRONG_HIRE: "text-success", HIRE: "text-success", LEAN_HIRE: "text-warning",
  LEAN_NO_HIRE: "text-warning", NO_HIRE: "text-danger", STRONG_NO_HIRE: "text-danger",
};
const RECO_LABEL: Record<string, string> = {
  STRONG_HIRE: "Strong Hire", HIRE: "Hire", LEAN_HIRE: "Lean Hire",
  LEAN_NO_HIRE: "Lean No Hire", NO_HIRE: "No Hire", STRONG_NO_HIRE: "Strong No Hire",
};

const ALL_STATUSES = ["PREP", "READY", "LIVE", "REVIEW", "COMPLETED", "ARCHIVED"];

export function Dashboard() {
  const [interviews, setInterviews] = useState<InterviewListItem[]>([]);
  const [filter, setFilter] = useState<string>("all");
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const { user, logout } = useAuthContext();
  const navigate = useNavigate();

  useEffect(() => {
    api.interviews.list().then(setInterviews).finally(() => setLoading(false));
  }, []);

  const filtered = filter === "all" ? interviews : interviews.filter((i) => i.status === filter);

  return (
    <div className="min-h-screen bg-surface-0 text-white">
      <header className="border-b border-surface-3 px-6 py-4 flex items-center justify-between">
        <div className="font-bold text-lg">VoxHelp Recruit</div>
        <div className="flex items-center gap-4">
          <span className="text-white/40 text-sm">{user?.name}</span>
          <button onClick={logout} className="text-white/40 hover:text-white text-sm transition-colors">Déconnexion</button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-6 py-8">
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-xl font-semibold">Entretiens</h1>
          <button
            onClick={() => setShowCreate(true)}
            className="px-4 py-2 bg-accent hover:bg-accent-dim rounded-lg text-sm font-medium transition-colors"
          >
            + Nouvel entretien
          </button>
        </div>

        {/* Status tabs */}
        <div className="flex gap-2 mb-6 flex-wrap">
          {["all", ...ALL_STATUSES].map((s) => (
            <button
              key={s}
              onClick={() => setFilter(s)}
              className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
                filter === s ? "bg-accent text-white" : "bg-surface-2 text-white/50 hover:text-white"
              }`}
            >
              {s === "all" ? "Tous" : STATUS_LABEL[s]}
            </button>
          ))}
        </div>

        {loading ? (
          <div className="text-white/30 text-sm">Chargement…</div>
        ) : filtered.length === 0 ? (
          <div className="text-white/30 text-sm text-center py-16">
            {filter === "all" ? "Aucun entretien. Créez-en un !" : "Aucun entretien dans ce statut."}
          </div>
        ) : (
          <div className="space-y-2">
            {filtered.map((i) => (
              <div
                key={i.id}
                onClick={() => navigate(`/interviews/${i.id}/prep`)}
                className="bg-surface-1 border border-surface-3 rounded-xl px-5 py-4 cursor-pointer hover:border-accent/40 transition-colors flex items-center gap-4"
              >
                <div className="flex-1 min-w-0">
                  <div className="font-medium truncate">{i.title}</div>
                  <div className="text-white/50 text-sm">{i.candidateName}</div>
                </div>
                <div className="flex items-center gap-3 shrink-0">
                  {i.overallScore !== null && (
                    <span className="text-white/60 text-sm">{i.overallScore}/5</span>
                  )}
                  {i.recommendation && (
                    <span className={`text-xs font-medium ${RECO_COLOR[i.recommendation] ?? ""}`}>
                      {RECO_LABEL[i.recommendation] ?? i.recommendation}
                    </span>
                  )}
                  <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${STATUS_COLOR[i.status] ?? ""}`}>
                    {STATUS_LABEL[i.status] ?? i.status}
                  </span>
                  {i.scheduledAt && (
                    <span className="text-white/30 text-xs">
                      {new Date(i.scheduledAt).toLocaleDateString("fr-FR")}
                    </span>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {showCreate && (
        <CreateModal
          onClose={() => setShowCreate(false)}
          onCreate={(id) => navigate(`/interviews/${id}/prep`)}
        />
      )}
    </div>
  );
}

function CreateModal({ onClose, onCreate }: { onClose: () => void; onCreate: (id: string) => void }) {
  const [title, setTitle] = useState("");
  const [candidateName, setCandidateName] = useState("");
  const [language, setLanguage] = useState("fr");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const interview = await api.interviews.create({ title, candidateName, language });
      onCreate(interview.id);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Erreur");
      setLoading(false);
    }
  }

  return (
    <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4" onClick={onClose}>
      <form
        onSubmit={handleCreate}
        className="bg-surface-1 border border-surface-3 rounded-xl p-6 w-full max-w-md space-y-4"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="font-semibold text-lg">Nouvel entretien</div>

        <div>
          <label className="block text-white/60 text-sm mb-1">Titre du poste</label>
          <input
            value={title} onChange={(e) => setTitle(e.target.value)} required
            placeholder="Backend Engineer — Round 2"
            className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm"
          />
        </div>
        <div>
          <label className="block text-white/60 text-sm mb-1">Nom du candidat</label>
          <input
            value={candidateName} onChange={(e) => setCandidateName(e.target.value)} required
            placeholder="John Doe"
            className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm"
          />
        </div>
        <div>
          <label className="block text-white/60 text-sm mb-1">Langue</label>
          <select
            value={language} onChange={(e) => setLanguage(e.target.value)}
            className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-accent text-sm"
          >
            {[["fr", "Français"], ["en", "English"], ["es", "Español"]].map(([v, l]) => (
              <option key={v} value={v}>{l}</option>
            ))}
          </select>
        </div>

        {error && <div className="text-danger text-sm">{error}</div>}

        <div className="flex gap-3 pt-2">
          <button type="button" onClick={onClose} className="flex-1 py-2 rounded-lg bg-surface-3 text-white/60 hover:text-white text-sm transition-colors">
            Annuler
          </button>
          <button type="submit" disabled={loading} className="flex-1 py-2 rounded-lg bg-accent hover:bg-accent-dim disabled:opacity-50 text-white text-sm font-medium transition-colors">
            {loading ? "…" : "Créer"}
          </button>
        </div>
      </form>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { api } from "../lib/api-client";
import type { InterviewDetail, QuestionItem } from "@voxhelp/shared";

const CATEGORY_COLOR: Record<string, string> = {
  TECHNICAL: "bg-accent/20 text-accent-light",
  SYSTEM_DESIGN: "bg-warning/20 text-warning",
  BEHAVIORAL: "bg-success/20 text-success",
  CULTURE_FIT: "bg-danger/20 text-danger",
  PROBLEM_SOLVING: "bg-purple-500/20 text-purple-300",
};

const DIFF_COLOR: Record<string, string> = {
  EASY: "text-success", MEDIUM: "text-warning", HARD: "text-danger",
};

export function InterviewPrep() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [interview, setInterview] = useState<InterviewDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [saving, setSaving] = useState(false);

  // Editable fields
  const [jobDescription, setJobDescription] = useState("");
  const [techStack, setTechStack] = useState("");
  const [cvContent, setCvContent] = useState("");
  const [candidateName, setCandidateName] = useState("");
  const [candidateEmail, setCandidateEmail] = useState("");
  const [language, setLanguage] = useState("fr");

  useEffect(() => {
    if (!id) return;
    api.interviews.get(id).then((data) => {
      setInterview(data);
      setJobDescription(data.jobDescription ?? "");
      setTechStack(data.techStack ?? "");
      setCvContent(data.cvContent ?? "");
      setCandidateName(data.candidateName);
      setCandidateEmail(data.candidateEmail ?? "");
      setLanguage(data.language);
    }).finally(() => setLoading(false));
  }, [id]);

  async function handleSave() {
    if (!id) return;
    setSaving(true);
    try {
      const updated = await api.interviews.update(id, { jobDescription, techStack, cvContent, candidateName, candidateEmail, language });
      setInterview(updated);
    } finally {
      setSaving(false);
    }
  }

  async function handleGenerate() {
    if (!id) return;
    setGenerating(true);
    try {
      await handleSave();
      const [questions, scorecard] = await Promise.all([
        api.interviews.generateQuestions(id),
        api.interviews.generateScorecard(id),
      ]);
      setInterview((prev) => prev ? { ...prev, questions, scorecard } : prev);
    } finally {
      setGenerating(false);
    }
  }

  async function handleStart() {
    if (!id) return;
    await api.interviews.patchStatus(id, "LIVE");
    navigate(`/interviews/${id}/live`);
  }

  if (loading || !interview) {
    return <div className="min-h-screen bg-surface-0 flex items-center justify-center text-white/40">Chargement…</div>;
  }

  const hasContent = interview.questions.length > 0 || interview.scorecard !== null;

  return (
    <div className="min-h-screen bg-surface-0 text-white">
      <header className="border-b border-surface-3 px-6 py-4 flex items-center gap-4">
        <button onClick={() => navigate("/dashboard")} className="text-white/40 hover:text-white transition-colors text-sm">
          ← Dashboard
        </button>
        <div className="flex-1 font-semibold">{interview.title}</div>
        <span className="px-2 py-0.5 rounded-full text-xs bg-surface-3 text-white/50">
          {interview.status}
        </span>
      </header>

      <div className="max-w-4xl mx-auto px-6 py-8 space-y-8">
        {/* Info candidate */}
        <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-4">
          <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Informations</div>
          <div className="grid grid-cols-2 gap-4">
            <Field label="Candidat" value={candidateName} onChange={setCandidateName} />
            <Field label="Email" value={candidateEmail} onChange={setCandidateEmail} placeholder="optionnel" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-white/60 text-sm mb-1">Langue</label>
              <select
                value={language} onChange={(e) => setLanguage(e.target.value)}
                className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-accent"
              >
                {[["fr", "Français"], ["en", "English"], ["es", "Español"]].map(([v, l]) => (
                  <option key={v} value={v}>{l}</option>
                ))}
              </select>
            </div>
            <Field label="Stack technique" value={techStack} onChange={setTechStack} placeholder="React, Node.js, AWS" />
          </div>
        </section>

        {/* JD */}
        <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
          <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Job Description</div>
          <textarea
            value={jobDescription} onChange={(e) => setJobDescription(e.target.value)}
            placeholder="Colle ou écris la description du poste ici…"
            rows={8}
            className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm resize-none"
          />
        </section>

        {/* CV */}
        <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
          <div className="font-medium text-white/80 text-sm uppercase tracking-wide">CV du candidat <span className="text-white/30 normal-case">(optionnel)</span></div>
          <textarea
            value={cvContent} onChange={(e) => setCvContent(e.target.value)}
            placeholder="Colle le contenu du CV ici…"
            rows={5}
            className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm resize-none"
          />
        </section>

        <div className="flex gap-3">
          <button
            onClick={handleSave}
            disabled={saving}
            className="px-4 py-2 rounded-lg bg-surface-3 hover:bg-surface-2 text-white/70 hover:text-white text-sm transition-colors disabled:opacity-50"
          >
            {saving ? "Sauvegarde…" : "Sauvegarder"}
          </button>
          <button
            onClick={handleGenerate}
            disabled={generating || !jobDescription.trim()}
            className="px-5 py-2 rounded-lg bg-accent hover:bg-accent-dim disabled:opacity-50 text-white text-sm font-medium transition-colors"
          >
            {generating ? "Génération…" : "Générer questions + scorecard"}
          </button>
        </div>

        {/* Questions */}
        {interview.questions.length > 0 && (
          <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
            <div className="font-medium text-white/80 text-sm uppercase tracking-wide">
              Questions générées <span className="text-white/40 normal-case">({interview.questions.length})</span>
            </div>
            <div className="space-y-3">
              {(interview.questions as QuestionItem[]).map((q, i) => (
                <div key={q.id} className="bg-surface-2 rounded-lg p-4 space-y-2">
                  <div className="flex items-start gap-3">
                    <span className="text-white/30 text-sm mt-0.5">{i + 1}.</span>
                    <div className="flex-1">
                      <div className="text-sm">{q.text}</div>
                      {q.expectedAnswer && (
                        <div className="text-white/40 text-xs mt-1 italic">{q.expectedAnswer}</div>
                      )}
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <span className={`px-2 py-0.5 rounded-full text-xs ${CATEGORY_COLOR[q.category] ?? "bg-surface-3 text-white/50"}`}>
                        {q.category}
                      </span>
                      <span className={`text-xs font-medium ${DIFF_COLOR[q.difficulty] ?? ""}`}>
                        {q.difficulty}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        )}

        {/* Scorecard */}
        {interview.scorecard && (
          <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
            <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Scorecard</div>
            <div className="space-y-2">
              {interview.scorecard.criteria.map((c) => (
                <div key={c.id} className="flex items-center gap-3 bg-surface-2 rounded-lg px-4 py-3">
                  <div className="flex-1">
                    <div className="text-sm font-medium">{c.name}</div>
                    {c.description && <div className="text-white/40 text-xs">{c.description}</div>}
                  </div>
                  <div className="flex gap-0.5">
                    {Array.from({ length: 3 }).map((_, i) => (
                      <span key={i} className={`text-lg leading-none ${i < c.weight ? "text-accent" : "text-surface-3"}`}>★</span>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </section>
        )}

        {hasContent && (
          <button
            onClick={handleStart}
            className="w-full py-3 rounded-xl bg-success/20 hover:bg-success/30 text-success font-semibold text-sm transition-colors border border-success/30"
          >
            ▶ Démarrer l'entretien
          </button>
        )}
      </div>
    </div>
  );
}

function Field({ label, value, onChange, placeholder }: { label: string; value: string; onChange: (v: string) => void; placeholder?: string }) {
  return (
    <div>
      <label className="block text-white/60 text-sm mb-1">{label}</label>
      <input
        value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder}
        className="w-full bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm"
      />
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { api } from "../lib/api-client";
import type { InterviewDetail } from "@voxhelp/shared";
import { useWebSocket } from "../hooks/useWebSocket";

const WS_URL = `ws://${window.location.host}/ws`;

export function InterviewLive() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [interview, setInterview] = useState<InterviewDetail | null>(null);
  const [askedIds, setAskedIds] = useState<Set<string>>(new Set());
  const [manualQuestion, setManualQuestion] = useState("");
  const [scores, setScores] = useState<Record<string, number>>({});
  const transcriptEndRef = useRef<HTMLDivElement>(null);

  const ws = useWebSocket(WS_URL);

  useEffect(() => {
    if (!id) return;
    api.interviews.get(id).then((data) => {
      setInterview(data);
      const asked = new Set(data.questions.filter((q) => q.isAsked).map((q) => q.id));
      setAskedIds(asked);
      ws.startSession(id);
    });
    return () => { ws.stopSession(); };
  }, [id]);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [ws.transcripts, ws.currentPartial]);

  async function handleStop() {
    ws.stopSession();
    if (!id) return;
    await api.interviews.patchStatus(id, "REVIEW");
    navigate(`/interviews/${id}/review`);
  }

  function handleMarkAsked(questionId: string) {
    setAskedIds((prev) => {
      const next = new Set(prev);
      next.has(questionId) ? next.delete(questionId) : next.add(questionId);
      return next;
    });
    ws.markAsked(questionId);
  }

  function handleSendQuestion(e: React.FormEvent) {
    e.preventDefault();
    if (!manualQuestion.trim()) return;
    ws.sendQuestion(manualQuestion.trim());
    setManualQuestion("");
  }

  function handleScore(criterionId: string, score: number) {
    setScores((prev) => ({ ...prev, [criterionId]: score }));
    if (interview?.scorecard?.id) {
      api.scorecards.updateCriterion(interview.scorecard.id, criterionId, score).catch(() => {});
    }
  }

  if (!interview) {
    return <div className="min-h-screen bg-surface-0 flex items-center justify-center text-white/40">Chargement…</div>;
  }

  return (
    <div className="min-h-screen bg-surface-0 text-white flex flex-col">
      {/* Header */}
      <header className="border-b border-surface-3 px-6 py-3 flex items-center gap-4">
        <div className="flex-1 font-semibold">{interview.title} — {interview.candidateName}</div>
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-danger animate-pulse" />
          <span className="text-danger text-sm font-medium">En cours</span>
        </div>
        <button
          onClick={handleStop}
          className="px-4 py-1.5 rounded-lg bg-danger/20 hover:bg-danger/30 text-danger text-sm font-medium transition-colors border border-danger/30"
        >
          ⏹ Stop
        </button>
      </header>

      <div className="flex-1 grid grid-cols-2 min-h-0">
        {/* Left — Transcript */}
        <div className="border-r border-surface-3 flex flex-col">
          <div className="px-4 py-3 border-b border-surface-3 text-xs text-white/40 uppercase tracking-wide font-medium">
            Transcription
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {ws.transcripts.map((t) => (
              <div key={t.id} className={`text-sm ${t.speaker === "INTERVIEWER" ? "text-white/50" : "text-white"}`}>
                <span className="text-white/30 text-xs mr-2">[{t.speaker === "INTERVIEWER" ? "👤" : "🎤"}]</span>
                {t.text}
              </div>
            ))}
            {ws.currentPartial && (
              <div className="text-sm text-white/40 italic">{ws.currentPartial}…</div>
            )}
            <div ref={transcriptEndRef} />
          </div>

          {/* Manual question input */}
          <form onSubmit={handleSendQuestion} className="p-4 border-t border-surface-3 flex gap-2">
            <input
              value={manualQuestion}
              onChange={(e) => setManualQuestion(e.target.value)}
              placeholder="Pose ta question ici…"
              className="flex-1 bg-surface-2 border border-surface-3 rounded-lg px-3 py-2 text-white placeholder-white/25 focus:outline-none focus:border-accent text-sm"
            />
            <button
              type="submit"
              className="px-3 py-2 bg-accent rounded-lg text-white text-sm hover:bg-accent-dim transition-colors"
            >
              ▶
            </button>
            <button
              type="button"
              onClick={() => ws.requestFollowup()}
              className="px-3 py-2 bg-surface-3 rounded-lg text-white/60 hover:text-white text-sm transition-colors"
              title="Demander une relance"
            >
              💡
            </button>
          </form>
        </div>

        {/* Right — 3 panels */}
        <div className="flex flex-col min-h-0 overflow-y-auto">
          {/* AI Suggestion */}
          <div className="border-b border-surface-3">
            <div className="px-4 py-3 border-b border-surface-3 text-xs text-white/40 uppercase tracking-wide font-medium">
              Assistant recruteur
            </div>
            <div className="p-4 min-h-[100px]">
              {ws.suggestion ? (
                <div className={`text-sm text-white ${ws.suggestion.isStreaming ? "cursor-blink" : ""}`}>
                  {ws.suggestion.text || <span className="text-white/30">Génération…</span>}
                </div>
              ) : (
                <div className="text-white/25 text-sm">Les suggestions de relance apparaîtront ici.</div>
              )}
            </div>
          </div>

          {/* Questions checklist */}
          {interview.questions.length > 0 && (
            <div className="border-b border-surface-3">
              <div className="px-4 py-3 border-b border-surface-3 text-xs text-white/40 uppercase tracking-wide font-medium">
                Questions à poser
              </div>
              <div className="p-4 space-y-2">
                {interview.questions.map((q) => (
                  <button
                    key={q.id}
                    onClick={() => handleMarkAsked(q.id)}
                    className="w-full flex items-start gap-3 text-left group"
                  >
                    <span className={`mt-0.5 w-4 h-4 rounded border shrink-0 flex items-center justify-center text-xs transition-colors ${
                      askedIds.has(q.id)
                        ? "border-success bg-success/20 text-success"
                        : "border-surface-3 group-hover:border-white/40"
                    }`}>
                      {askedIds.has(q.id) && "✓"}
                    </span>
                    <span className={`text-sm leading-snug ${askedIds.has(q.id) ? "line-through text-white/30" : "text-white/80"}`}>
                      {q.text}
                    </span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Live scorecard */}
          {interview.scorecard && (
            <div>
              <div className="px-4 py-3 border-b border-surface-3 text-xs text-white/40 uppercase tracking-wide font-medium">
                Scorecard live
              </div>
              <div className="p-4 space-y-3">
                {interview.scorecard.criteria.map((c) => (
                  <div key={c.id}>
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-sm text-white/70">{c.name}</span>
                      {scores[c.id] && <span className="text-xs text-white/40">{scores[c.id]}/5</span>}
                    </div>
                    <div className="flex gap-1">
                      {[1, 2, 3, 4, 5].map((star) => (
                        <button
                          key={star}
                          onClick={() => handleScore(c.id, star)}
                          className={`text-xl leading-none transition-colors ${
                            (scores[c.id] ?? 0) >= star ? "text-accent" : "text-surface-3 hover:text-accent/50"
                          }`}
                        >
                          ★
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { api } from "../lib/api-client";
import type { InterviewDetail, ScorecardDetail, SummaryDetail } from "@voxhelp/shared";

const RECO_COLOR: Record<string, string> = {
  STRONG_HIRE: "text-success border-success/30 bg-success/10",
  HIRE: "text-success border-success/30 bg-success/10",
  LEAN_HIRE: "text-warning border-warning/30 bg-warning/10",
  LEAN_NO_HIRE: "text-warning border-warning/30 bg-warning/10",
  NO_HIRE: "text-danger border-danger/30 bg-danger/10",
  STRONG_NO_HIRE: "text-danger border-danger/30 bg-danger/10",
};
const RECO_LABEL: Record<string, string> = {
  STRONG_HIRE: "Strong Hire ✅", HIRE: "Hire ✅",
  LEAN_HIRE: "Lean Hire ⚠️", LEAN_NO_HIRE: "Lean No Hire ⚠️",
  NO_HIRE: "No Hire ❌", STRONG_NO_HIRE: "Strong No Hire ❌",
};

export function InterviewReview() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [interview, setInterview] = useState<InterviewDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [showTranscript, setShowTranscript] = useState(false);

  useEffect(() => {
    if (!id) return;
    api.interviews.get(id).then(setInterview).finally(() => setLoading(false));
  }, [id]);

  async function handleGenerateAnalysis() {
    if (!id) return;
    setGenerating(true);
    try {
      const [summary, scorecard] = await Promise.all([
        api.interviews.generateSummary(id),
        api.interviews.generateScoring(id),
      ]);
      setInterview((prev) => prev ? { ...prev, summary: summary as SummaryDetail, scorecard: scorecard as ScorecardDetail } : prev);
    } finally {
      setGenerating(false);
    }
  }

  async function handleComplete() {
    if (!id) return;
    await api.interviews.patchStatus(id, "COMPLETED");
    navigate("/dashboard");
  }

  if (loading || !interview) {
    return <div className="min-h-screen bg-surface-0 flex items-center justify-center text-white/40">Chargement…</div>;
  }

  const { summary, scorecard } = interview;

  return (
    <div className="min-h-screen bg-surface-0 text-white">
      <header className="border-b border-surface-3 px-6 py-4 flex items-center gap-4">
        <button onClick={() => navigate("/dashboard")} className="text-white/40 hover:text-white transition-colors text-sm">
          ← Dashboard
        </button>
        <div className="flex-1 font-semibold">{interview.title} — {interview.candidateName}</div>
        <span className="px-2 py-0.5 rounded-full text-xs bg-surface-3 text-white/50">REVIEW</span>
      </header>

      <div className="max-w-4xl mx-auto px-6 py-8 space-y-8">
        {!summary && (
          <button
            onClick={handleGenerateAnalysis}
            disabled={generating}
            className="w-full py-3 rounded-xl bg-accent hover:bg-accent-dim disabled:opacity-50 text-white font-semibold text-sm transition-colors"
          >
            {generating ? "Génération de l'analyse…" : "Générer l'analyse IA"}
          </button>
        )}

        {summary && (
          <>
            {/* Summary */}
            <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-4">
              <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Résumé</div>
              <p className="text-sm text-white/80 leading-relaxed">{summary.summary}</p>
            </section>

            {/* Strengths / Weaknesses / Red flags */}
            <div className="grid grid-cols-1 gap-4">
              {summary.strengths.length > 0 && (
                <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
                  <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Points forts</div>
                  <ul className="space-y-1">
                    {summary.strengths.map((s, i) => (
                      <li key={i} className="text-sm text-white/80 flex gap-2">
                        <span className="text-success shrink-0">✅</span>{s}
                      </li>
                    ))}
                  </ul>
                </section>
              )}

              {summary.weaknesses.length > 0 && (
                <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
                  <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Points faibles</div>
                  <ul className="space-y-1">
                    {summary.weaknesses.map((s, i) => (
                      <li key={i} className="text-sm text-white/80 flex gap-2">
                        <span className="text-warning shrink-0">⚠️</span>{s}
                      </li>
                    ))}
                  </ul>
                </section>
              )}

              {summary.redFlags.length > 0 && (
                <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-3">
                  <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Red flags</div>
                  <ul className="space-y-1">
                    {summary.redFlags.map((s, i) => (
                      <li key={i} className="text-sm text-white/80 flex gap-2">
                        <span className="text-danger shrink-0">🚩</span>{s}
                      </li>
                    ))}
                  </ul>
                </section>
              )}
            </div>

            {/* Scorecard */}
            {scorecard && (
              <section className="bg-surface-1 border border-surface-3 rounded-xl p-6 space-y-4">
                <div className="font-medium text-white/80 text-sm uppercase tracking-wide">Scorecard finale</div>
                <div className="space-y-3">
                  {scorecard.criteria.map((c) => (
                    <div key={c.id} className="flex items-center gap-4">
                      <div className="flex-1">
                        <div className="text-sm font-medium">{c.name}</div>
                        {c.notes && <div className="text-white/40 text-xs">{c.notes}</div>}
                      </div>
                      <div className="flex gap-0.5">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <span key={star} className={`text-lg leading-none ${(c.score ?? 0) >= star ? "text-accent" : "text-surface-3"}`}>★</span>
                        ))}
                      </div>
                      <span className="text-sm text-white/40 w-8 text-right">{c.score ?? "–"}/5</span>
                      <div className="flex gap-0.5">
                        {Array.from({ length: 3 }).map((_, i) => (
                          <span key={i} className={`text-sm leading-none ${i < c.weight ? "text-accent/60" : "text-surface-3"}`}>★</span>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>

                <div className="border-t border-surface-3 pt-4 flex items-center justify-between">
                  <div>
                    <div className="text-white/50 text-sm">Score global</div>
                    <div className="text-2xl font-bold">{scorecard.overallScore ?? "–"}<span className="text-white/30 text-base">/5</span></div>
                  </div>
                  {scorecard.recommendation && (
                    <div className={`px-4 py-2 rounded-xl text-sm font-semibold border ${RECO_COLOR[scorecard.recommendation] ?? ""}`}>
                      {RECO_LABEL[scorecard.recommendation] ?? scorecard.recommendation}
                    </div>
                  )}
                </div>
              </section>
            )}
          </>
        )}

        {/* Transcript accordion */}
        <section className="bg-surface-1 border border-surface-3 rounded-xl overflow-hidden">
          <button
            onClick={() => setShowTranscript(!showTranscript)}
            className="w-full px-6 py-4 flex items-center justify-between text-sm font-medium text-white/70 hover:text-white transition-colors"
          >
            <span className="uppercase tracking-wide text-xs">Transcription complète</span>
            <span>{showTranscript ? "▲" : "▼"}</span>
          </button>
          {showTranscript && (
            <div className="border-t border-surface-3 p-6 space-y-2 max-h-96 overflow-y-auto">
              {interview.transcript?.length > 0 ? (
                (interview.transcript as { id: string; text: string; speaker: string }[]).map((t) => (
                  <div key={t.id} className="text-sm">
                    <span className="text-white/30 text-xs mr-2">[{t.speaker}]</span>
                    <span className="text-white/70">{t.text}</span>
                  </div>
                ))
              ) : (
                <div className="text-white/30 text-sm">Aucune transcription enregistrée.</div>
              )}
            </div>
          )}
        </section>

        {/* Actions */}
        <div className="flex gap-3">
          <button
            onClick={handleComplete}
            className="flex-1 py-3 rounded-xl bg-success/20 hover:bg-success/30 text-success font-semibold text-sm transition-colors border border-success/30"
          >
            ✅ Marquer comme complété
          </button>
        </div>
      </div>
    </div>
  );
}

