input.content:
// ═══════════════════════════════════════
// Session config
// ═══════════════════════════════════════

export type DemoStep = "prep" | "live" | "report";

export type InterviewLanguage = "fr" | "en" | "es" | "pt" | "zh";

export interface SessionConfig {
  language: InterviewLanguage;
  jobDescription: string;
  candidateName: string;
  techStack?: string;
  questions?: GeneratedQuestion[];
  scorecard?: ScorecardCriterion[];
}

// ═══════════════════════════════════════
// Questions & Scorecard (generated by AI)
// ═══════════════════════════════════════

export interface GeneratedQuestion {
  id: string;
  text: string;
  category: "TECHNICAL" | "SYSTEM_DESIGN" | "BEHAVIORAL" | "CULTURE_FIT";
  difficulty: "EASY" | "MEDIUM" | "HARD";
  expectedAnswer: string;
  isAsked: boolean;
}

export interface ScorecardCriterion {
  id: string;
  name: string;
  description: string;
  weight: number; // 1-3
  score: number | null; // 1-5 or null
  notes: string | null;
}

export interface JobAnalysis {
  summary: string;
  criticalSkills: { name: string; why: string }[];
  niceToHave: string[];
  questions: GeneratedQuestion[];
  scorecard: ScorecardCriterion[];
}

// ═══════════════════════════════════════
// Tech Translation (live)
// ═══════════════════════════════════════

export interface TechTranslation {
  term: string;
  definition: string;
  relatedTechs: string[];
  criticality: "HIGH" | "MEDIUM" | "LOW";
}

// ═══════════════════════════════════════
// Transcript
// ═══════════════════════════════════════

export interface TranscriptEntry {
  id: string;
  text: string;
  timestamp: number;
}

// ═══════════════════════════════════════
// Report (post-call)
// ═══════════════════════════════════════

export interface InterviewReport {
  summary: string;
  strengths: string[];
  weaknesses: string[];
  redFlags: string[];
  recommendation: "STRONG_HIRE" | "HIRE" | "LEAN_HIRE" | "LEAN_NO_HIRE" | "NO_HIRE";
  overallScore: number; // 1-5
  scoredCriteria: ScorecardCriterion[];
}

// ═══════════════════════════════════════
// WebSocket messages
// ═══════════════════════════════════════

export type ClientMessage =
  | { type: "session:start"; config: SessionConfig }
  | { type: "session:stop" }
  | { type: "audio:chunk"; data: string }
  | { type: "question:mark-asked"; questionId: string }
  | { type: "criterion:score"; criterionId: string; score: number }
  | { type: "ping" };

export type ServerMessage =
  | { type: "session:ready"; sessionId: string }
  | { type: "session:error"; error: string }
  | { type: "transcript:partial"; text: string }
  | { type: "transcript:final"; text: string }
  | { type: "tech:translation"; translation: TechTranslation }
  | { type: "assist:start" }
  | { type: "assist:chunk"; text: string }
  | { type: "assist:done"; fullText: string }
  | { type: "assist:error"; error: string }
  | { type: "pong" };

// ═══════════════════════════════════════
// Constants
// ═══════════════════════════════════════

export const AUDIO_SAMPLE_RATE = 16000;
export const AUDIO_CHANNELS = 1;
export const AUDIO_CHUNK_MS = 250;
export const WS_PING_INTERVAL_MS = 30000;
export const DEBOUNCE_MS = 1800;

export function createId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

export function buildJobAnalysisPrompt(
  jobDescription: string,
  techStack?: string
): { system: string; user: string } {
  return {
    system: `Tu es un expert en recrutement technique avec 15 ans d'expérience.
Tu analyses des fiches de poste pour aider les recruteurs non-techniques.

Tu dois fournir :
1. Un résumé clair du poste en 2-3 phrases, sans jargon
2. Les compétences critiques (MUST-HAVE) avec une explication simple de chaque techno
3. Les compétences secondaires (NICE-TO-HAVE)
4. 8-10 questions d'entretien réparties en catégories
5. 6-8 critères d'évaluation avec pondération

Réponds UNIQUEMENT en JSON valide, sans backticks, sans markdown :
{
  "summary": "Description claire du poste en langage non-technique",
  "criticalSkills": [
    { "name": "Nom de la techno", "why": "Explication simple de ce que c'est et pourquoi c'est important pour ce poste" }
  ],
  "niceToHave": ["Techno 1", "Techno 2"],
  "questions": [
    {
      "text": "La question à poser",
      "category": "TECHNICAL|SYSTEM_DESIGN|BEHAVIORAL|CULTURE_FIT",
      "difficulty": "EASY|MEDIUM|HARD",
      "expectedAnswer": "Ce qu'un bon candidat devrait répondre en 2-3 phrases"
    }
  ],
  "scorecard": [
    {
      "name": "Nom du critère",
      "description": "Ce qu'on évalue concrètement",
      "weight": 1
    }
  ]
}`,
    user: `FICHE DE POSTE :\n${jobDescription}${techStack ? `\n\nSTACK TECHNIQUE MENTIONNÉE : ${techStack}` : ""}`,
  };
}

export function buildLiveAssistPrompt(
  jobDescription: string,
  questions: { text: string; isAsked: boolean }[],
  scorecard: { name: string; description: string }[]
): string {
  const unanswered = questions
    .filter((q) => !q.isAsked)
    .map((q) => `- ${q.text}`)
    .join("\n");
  const criteria = scorecard
    .map((c) => `- ${c.name}: ${c.description}`)
    .join("\n");

  return `Tu es un copilote IA pour recruteur tech. Tu assistes le recruteur PENDANT un call avec un candidat.

Tu reçois la transcription de ce qui vient d'être dit.

Tu dois faire DEUX choses dans ta réponse :

1. TRADUCTION TECH : si un terme technique est mentionné (framework, pattern, outil, concept), explique-le simplement en 1 phrase et indique les technos associées.

2. ÉVALUATION + RELANCE : évalue la pertinence de ce que le candidat vient de dire par rapport au poste, et suggère UNE question de relance.

Format de réponse (2-4 phrases max) :
- Si terme technique détecté : "🔍 [Terme] : [explication]. Lié à : [technos]."
- Puis : "✅ Bonne réponse" ou "⚠️ À creuser" suivi d'une question de relance.
- Ou juste la relance si pas de terme technique.

Sois CONCIS. Le recruteur lit ça en temps réel pendant un call.

FICHE DE POSTE : ${jobDescription}

QUESTIONS RESTANTES À POSER :
${unanswered || "Toutes posées"}

CRITÈRES D'ÉVALUATION :
${criteria}`;
}

export function buildTechTranslatePrompt(): string {
  return `Tu es un dictionnaire technique vivant pour recruteurs non-techniques.

Tu reçois un extrait de conversation d'entretien technique.
Si un terme technique, un framework, un pattern, un outil ou un concept est mentionné, explique-le.

Réponds UNIQUEMENT en JSON valide, sans backticks :
{
  "translations": [
    {
      "term": "Le terme détecté",
      "definition": "Explication simple en 1-2 phrases, comme si tu parlais à quelqu'un qui n'a jamais codé",
      "relatedTechs": ["Techno liée 1", "Techno liée 2"],
      "criticality": "HIGH|MEDIUM|LOW"
    }
  ]
}

Si aucun terme technique n'est détecté, réponds : {"translations": []}

IMPORTANT : ne traduis pas les termes basiques que tout le monde connaît (email, API, web, etc.). Concentre-toi sur les technos spécifiques (frameworks, patterns, outils, langages, concepts d'architecture).`;
}

export function buildReportPrompt(
  jobDescription: string,
  transcriptEntries: { text: string; timestamp: number }[],
  scorecard: { id: string; name: string; description: string; weight: number }[]
): { system: string; user: string } {
  const transcript = transcriptEntries.map((t) => t.text).join("\n");
  const criteria = scorecard
    .map((c) => `- ${c.name} (poids ${c.weight}): ${c.description}`)
    .join("\n");

  return {
    system: `Tu es un expert en évaluation de recrutement technique.
Tu analyses la transcription d'un entretien et tu génères un rapport structuré.

Score chaque critère de 1 à 5. Donne une recommandation globale.

Réponds UNIQUEMENT en JSON valide, sans backticks :
{
  "summary": "Résumé de l'entretien en 3-4 phrases",
  "strengths": ["Point fort 1", "Point fort 2"],
  "weaknesses": ["Point faible 1"],
  "redFlags": ["Red flag 1"],
  "recommendation": "STRONG_HIRE|HIRE|LEAN_HIRE|LEAN_NO_HIRE|NO_HIRE",
  "overallScore": 3,
  "scoredCriteria": [
    {
      "id": "id du critère",
      "name": "nom",
      "description": "description",
      "weight": 1,
      "score": 3,
      "notes": "Justification en 1 phrase"
    }
  ]
}`,
    user: `FICHE DE POSTE :\n${jobDescription}\n\nCRITÈRES D'ÉVALUATION :\n${criteria}\n\nTRANSCRIPTION :\n${transcript || "(aucune transcription disponible)"}`,
  };
}

import Anthropic from "@anthropic-ai/sdk";

const anthropic = new Anthropic();

interface StreamCallbacks {
  onStart: () => void;
  onChunk: (text: string) => void;
  onDone: (fullText: string) => void;
  onError: (error: string) => void;
}

export async function generateFromPrompt(
  systemPrompt: string,
  userMessage: string,
  callbacks: StreamCallbacks
): Promise<void> {
  try {
    callbacks.onStart();

    const stream = anthropic.messages.stream({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1024,
      system: systemPrompt,
      messages: [{ role: "user", content: userMessage }],
    });

    let fullText = "";

    for await (const event of stream) {
      if (
        event.type === "content_block_delta" &&
        event.delta.type === "text_delta"
      ) {
        fullText += event.delta.text;
        callbacks.onChunk(event.delta.text);
      }
    }

    callbacks.onDone(fullText);
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown LLM error";
    callbacks.onError(message);
  }
}

export async function callClaudeJSON<T>(
  systemPrompt: string,
  userMessage: string
): Promise<T> {
  const message = await anthropic.messages.create({
    model: "claude-sonnet-4-20250514",
    max_tokens: 4096,
    system: systemPrompt,
    messages: [{ role: "user", content: userMessage }],
  });

  const content = message.content[0];
  if (content.type !== "text") throw new Error("Unexpected response type from Claude");

  return JSON.parse(content.text) as T;
}

import type { FastifyInstance } from "fastify";
import type {
  JobAnalysis,
  GeneratedQuestion,
  InterviewReport,
  ScorecardCriterion,
} from "@voxhelp/shared";
import { createId } from "@voxhelp/shared";
import { callClaudeJSON } from "./llm.js";
import { buildJobAnalysisPrompt } from "./prompts/job-analysis.js";
import { buildReportPrompt } from "./prompts/report.js";

interface RawJobAnalysis {
  summary: string;
  criticalSkills: { name: string; why: string }[];
  niceToHave: string[];
  questions: {
    text: string;
    category: string;
    difficulty: string;
    expectedAnswer: string;
  }[];
  scorecard: {
    name: string;
    description: string;
    weight: number;
  }[];
}

export async function registerRoutes(app: FastifyInstance): Promise<void> {
  app.post("/api/analyze-job", async (request, reply) => {
    const { jobDescription, techStack } = request.body as {
      jobDescription: string;
      techStack?: string;
    };

    if (!jobDescription?.trim()) {
      return reply.status(400).send({ error: "jobDescription is required" });
    }

    try {
      const { system, user } = buildJobAnalysisPrompt(jobDescription, techStack);
      const raw = await callClaudeJSON<RawJobAnalysis>(system, user);

      const analysis: JobAnalysis = {
        summary: raw.summary,
        criticalSkills: raw.criticalSkills,
        niceToHave: raw.niceToHave,
        questions: raw.questions.map((q) => ({
          id: createId(),
          text: q.text,
          category: q.category as GeneratedQuestion["category"],
          difficulty: q.difficulty as GeneratedQuestion["difficulty"],
          expectedAnswer: q.expectedAnswer,
          isAsked: false,
        })),
        scorecard: raw.scorecard.map((c) => ({
          id: createId(),
          name: c.name,
          description: c.description,
          weight: c.weight,
          score: null,
          notes: null,
        })),
      };

      return analysis;
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Unknown error";
      console.error("[routes] analyze-job error:", msg);
      return reply.status(500).send({ error: msg });
    }
  });

  app.post("/api/generate-report", async (request, reply) => {
    const { jobDescription, transcript, scorecard } = request.body as {
      jobDescription: string;
      transcript: { text: string; timestamp: number }[];
      scorecard: ScorecardCriterion[];
    };

    if (!jobDescription?.trim()) {
      return reply.status(400).send({ error: "jobDescription is required" });
    }

    try {
      const { system, user } = buildReportPrompt(jobDescription, transcript ?? [], scorecard ?? []);
      const report = await callClaudeJSON<InterviewReport>(system, user);
      return report;
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Unknown error";
      console.error("[routes] generate-report error:", msg);
      return reply.status(500).send({ error: msg });
    }
  });
}

import type { WebSocket } from "ws";
import type {
  ClientMessage,
  ServerMessage,
  SessionConfig,
  GeneratedQuestion,
  ScorecardCriterion,
  TechTranslation,
} from "@voxhelp/shared";
import { DeepgramSTT } from "./deepgram.js";
import { generateFromPrompt, callClaudeJSON } from "./llm.js";
import { buildLiveAssistPrompt } from "./prompts/live-assist.js";
import { buildTechTranslatePrompt } from "./prompts/tech-translate.js";

export class Session {
  private ws: WebSocket;
  private stt: DeepgramSTT | null = null;
  private config: SessionConfig | null = null;
  private questions: GeneratedQuestion[] = [];
  private scorecard: ScorecardCriterion[] = [];
  private transcriptBuffer: string[] = [];
  private debounceTimer: ReturnType<typeof setTimeout> | null = null;
  private isProcessingAssist = false;
  private pendingTranscript: string | null = null;
  private readonly DEBOUNCE_MS = 1800;

  constructor(ws: WebSocket) {
    this.ws = ws;
    this.setupHandlers();
  }

  private setupHandlers(): void {
    this.ws.on("message", (data) => {
      try {
        const message: ClientMessage = JSON.parse(data.toString());
        this.handleMessage(message);
      } catch {
        if (Buffer.isBuffer(data) && this.stt) {
          this.stt.sendAudio(data);
        }
      }
    });

    this.ws.on("close", () => this.cleanup());
    this.ws.on("error", (err) => {
      console.error("[Session] WS error:", err.message);
      this.cleanup();
    });
  }

  private handleMessage(message: ClientMessage): void {
    switch (message.type) {
      case "session:start":
        this.startSession(message.config);
        break;
      case "session:stop":
        this.cleanup();
        break;
      case "audio:chunk":
        this.handleAudioChunk(message.data);
        break;
      case "question:mark-asked":
        this.toggleQuestion(message.questionId);
        break;
      case "criterion:score":
        this.updateScore(message.criterionId, message.score);
        break;
      case "ping":
        this.send({ type: "pong" });
        break;
    }
  }

  private startSession(config: SessionConfig): void {
    this.config = config;
    this.questions = config.questions ? [...config.questions] : [];
    this.scorecard = config.scorecard ? [...config.scorecard] : [];
    this.transcriptBuffer = [];

    this.stt = new DeepgramSTT(config.language, {
      onPartial: (text) => this.send({ type: "transcript:partial", text }),
      onFinal: (text) => this.handleFinalTranscript(text),
      onError: (err) => this.send({ type: "session:error", error: err }),
    });

    this.stt.connect();

    const sessionId = `session_${Date.now()}`;
    this.send({ type: "session:ready", sessionId });
    console.log(`[Session] Started: language=${config.language}, candidate=${config.candidateName}`);
  }

  private handleAudioChunk(base64Data: string): void {
    if (!this.stt) return;
    const buffer = Buffer.from(base64Data, "base64");
    this.stt.sendAudio(buffer);
  }

  private handleFinalTranscript(text: string): void {
    if (!text.trim()) return;

    this.send({ type: "transcript:final", text });
    this.transcriptBuffer.push(text);

    if (this.debounceTimer) clearTimeout(this.debounceTimer);

    this.debounceTimer = setTimeout(() => {
      const fullText = this.transcriptBuffer.join(" ");
      this.transcriptBuffer = [];

      if (fullText.trim().length < 10) return;

      if (this.isProcessingAssist) {
        this.pendingTranscript = fullText;
        return;
      }

      this.processTranscript(fullText);
    }, this.DEBOUNCE_MS);
  }

  private async processTranscript(transcript: string): Promise<void> {
    if (!this.config) return;

    this.isProcessingAssist = true;

    await Promise.all([
      this.runTechTranslation(transcript),
      this.runAssist(transcript),
    ]);

    this.isProcessingAssist = false;

    if (this.pendingTranscript) {
      const pending = this.pendingTranscript;
      this.pendingTranscript = null;
      this.processTranscript(pending);
    }
  }

  private async runTechTranslation(transcript: string): Promise<void> {
    try {
      const systemPrompt = buildTechTranslatePrompt();
      const result = await callClaudeJSON<{ translations: TechTranslation[] }>(
        systemPrompt,
        `TRANSCRIPTION:\n"${transcript}"`
      );
      for (const translation of result.translations) {
        this.send({ type: "tech:translation", translation });
      }
    } catch (err) {
      console.error("[Session] Tech translation error:", err instanceof Error ? err.message : err);
    }
  }

  private async runAssist(transcript: string): Promise<void> {
    if (!this.config) return;

    const systemPrompt = buildLiveAssistPrompt(
      this.config.jobDescription,
      this.questions,
      this.scorecard
    );

    await generateFromPrompt(
      systemPrompt,
      `Ce qui vient d'être dit :\n"${transcript}"`,
      {
        onStart: () => this.send({ type: "assist:start" }),
        onChunk: (text) => this.send({ type: "assist:chunk", text }),
        onDone: (fullText) => this.send({ type: "assist:done", fullText }),
        onError: (error) => this.send({ type: "assist:error", error }),
      }
    );
  }

  private toggleQuestion(questionId: string): void {
    const q = this.questions.find((q) => q.id === questionId);
    if (q) q.isAsked = !q.isAsked;
  }

  private updateScore(criterionId: string, score: number): void {
    const c = this.scorecard.find((c) => c.id === criterionId);
    if (c) c.score = score;
  }

  private send(message: ServerMessage): void {
    if (this.ws.readyState === this.ws.OPEN) {
      this.ws.send(JSON.stringify(message));
    }
  }

  private cleanup(): void {
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
    this.transcriptBuffer = [];
    if (this.stt) {
      this.stt.close();
      this.stt = null;
    }
    this.config = null;
    this.questions = [];
    this.scorecard = [];
    console.log("[Session] Cleaned up");
  }
}

