};

interface QuestionChecklistProps {
  questions: GeneratedQuestion[];
  onToggle: (id: string) => void;
}

export function QuestionChecklist({ questions, onToggle }: QuestionChecklistProps) {
  const byCategory = questions.reduce(
    (acc, q) => {
      (acc[q.category] ??= []).push(q);
      return acc;
    },
    {} as Record<GeneratedQuestion["category"], GeneratedQuestion[]>
  );

  return (
    <div className="space-y-3">
      {(Object.entries(byCategory) as [GeneratedQuestion["category"], GeneratedQuestion[]][]).map(
        ([cat, qs]) => (
          <div key={cat}>
            <p className="text-[10px] uppercase tracking-wider text-[#5A5F72] font-semibold mb-1.5">
              {CATEGORY_LABELS[cat]}
            </p>
            <div className="space-y-1">
              {qs.map((q) => (
                <button
                  key={q.id}
                  onClick={() => onToggle(q.id)}
                  className="w-full flex items-start gap-2 text-left group"
                >
                  <div
                    className={`mt-0.5 w-4 h-4 rounded border flex-shrink-0 flex items-center justify-center transition-colors ${
                      q.isAsked
                        ? "bg-[#0FAA6C] border-[#0FAA6C]"
                        : "border-[#DFE1EA] group-hover:border-[#3D5AFE]"
                    }`}
                  >
                    {q.isAsked && (
                      <svg className="w-2.5 h-2.5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                    )}
                  </div>
                  <span
                    className={`text-xs leading-relaxed transition-colors ${
                      q.isAsked ? "line-through text-[#5A5F72]" : "text-[#1A1D26] group-hover:text-[#3D5AFE]"
                    }`}
                  >
                    {q.text}
                  </span>
                  <span className={`text-[10px] ml-auto flex-shrink-0 ${DIFFICULTY_COLORS[q.difficulty]}`}>
                    {q.difficulty === "EASY" ? "●" : q.difficulty === "MEDIUM" ? "●●" : "●●●"}
                  </span>
                </button>
              ))}
            </div>
          </div>
        )
      )}
    </div>
  );
}

import type { ScorecardCriterion } from "@voxhelp/shared";

interface ScorecardPanelProps {
  scorecard: ScorecardCriterion[];
  onScore: (criterionId: string, score: number) => void;
  readonly?: boolean;
}

function StarRating({
  score,
  onChange,
  readonly,
}: {
  score: number | null;
  onChange?: (score: number) => void;
  readonly?: boolean;
}) {
  return (
    <div className="flex gap-0.5">
      {[1, 2, 3, 4, 5].map((star) => (
        <button
          key={star}
          onClick={() => !readonly && onChange?.(star)}
          disabled={readonly}
          className={`text-base leading-none transition-colors ${
            readonly ? "cursor-default" : "cursor-pointer hover:scale-110"
          } ${score !== null && star <= score ? "text-[#E8850A]" : "text-[#DFE1EA]"}`}
        >
          ★
        </button>
      ))}
    </div>
  );
}

export function ScorecardPanel({ scorecard, onScore, readonly }: ScorecardPanelProps) {
  return (
    <div className="space-y-2">
      {scorecard.map((c) => (
        <div key={c.id} className="flex items-center justify-between gap-2">
          <div className="min-w-0">
            <p className="text-xs font-medium text-[#1A1D26] truncate">{c.name}</p>
            <p className="text-[10px] text-[#5A5F72]">Poids {c.weight}</p>
          </div>
          <div className="flex items-center gap-1.5 flex-shrink-0">
            <StarRating
              score={c.score}
              onChange={(score) => onScore(c.id, score)}
              readonly={readonly}
            />
            <span className="text-xs text-[#5A5F72] w-6 text-right">
              {c.score !== null ? `${c.score}/5` : "-"}
            </span>
          </div>
        </div>
      ))}
    </div>
  );
}

import { useState } from "react";
