  50% { opacity: 0; }
}

.cursor-blink::after {
  content: "▊";
  animation: blink 0.8s step-end infinite;
  color: #3D5AFE;
  margin-left: 2px;
}

@keyframes fade-in {
  from { opacity: 0; transform: translateY(4px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-fade-in {
  animation: fade-in 0.25s ease-out;
}

import { useCallback, useEffect, useRef, useState } from "react";

type AudioSource = "microphone" | "tab";

interface UseAudioCaptureReturn {
  isCapturing: boolean;
  isSpeaking: boolean;
  audioSource: AudioSource | null;
  startMicrophone: () => Promise<void>;
  startTabCapture: () => Promise<void>;
  stop: () => void;
  error: string | null;
}

const SAMPLE_RATE = 16000;
const CHUNK_MS = 250;
const SPEAKING_THRESHOLD = 0.01; // RMS amplitude threshold
const SILENCE_DEBOUNCE_MS = 400;

function float32ToBase64(float32: Float32Array): string {
  const int16 = new Int16Array(float32.length);
  for (let i = 0; i < float32.length; i++) {
    const s = Math.max(-1, Math.min(1, float32[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
  }
  const uint8 = new Uint8Array(int16.buffer);
  let binary = "";
  for (let i = 0; i < uint8.length; i++) {
    binary += String.fromCharCode(uint8[i]);
  }
  return btoa(binary);
}

function getRMS(buffer: Float32Array): number {
  let sum = 0;
  for (let i = 0; i < buffer.length; i++) sum += buffer[i] * buffer[i];
  return Math.sqrt(sum / buffer.length);
}

export function useAudioCapture(
  onAudioChunk: (base64: string) => void
): UseAudioCaptureReturn {
  const [isCapturing, setIsCapturing] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [audioSource, setAudioSource] = useState<AudioSource | null>(null);
  const [error, setError] = useState<string | null>(null);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const silenceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const onAudioChunkRef = useRef(onAudioChunk);
  onAudioChunkRef.current = onAudioChunk;

  const startCapture = useCallback(async (stream: MediaStream, source: AudioSource) => {
    const ctx = new AudioContext({ sampleRate: SAMPLE_RATE });
    const source_ = ctx.createMediaStreamSource(stream);
    // ScriptProcessorNode: chunk size = SAMPLE_RATE * CHUNK_MS / 1000
    const bufferSize = Math.pow(2, Math.round(Math.log2(SAMPLE_RATE * CHUNK_MS / 1000)));
    const processor = ctx.createScriptProcessor(bufferSize, 1, 1);

    processor.onaudioprocess = (e) => {
      const frame = e.inputBuffer.getChannelData(0);
      const rms = getRMS(frame);

      if (rms > SPEAKING_THRESHOLD) {
        if (silenceTimerRef.current) {
          clearTimeout(silenceTimerRef.current);
          silenceTimerRef.current = null;
        }
        setIsSpeaking(true);
        onAudioChunkRef.current(float32ToBase64(new Float32Array(frame)));
      } else {
        if (!silenceTimerRef.current) {
          silenceTimerRef.current = setTimeout(() => {
            setIsSpeaking(false);
            silenceTimerRef.current = null;
          }, SILENCE_DEBOUNCE_MS);
        }
      }
    };

    source_.connect(processor);
    processor.connect(ctx.destination);

    audioCtxRef.current = ctx;
    processorRef.current = processor;
    streamRef.current = stream;
    setAudioSource(source);
    setIsCapturing(true);
    setError(null);
  }, []);

  const startMicrophone = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: { sampleRate: SAMPLE_RATE, channelCount: 1, echoCancellation: true, noiseSuppression: true },
      });
      await startCapture(stream, "microphone");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Microphone access denied");
    }
  }, [startCapture]);

  const startTabCapture = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true, audio: true });
      stream.getVideoTracks().forEach((t) => t.stop());
      const audioTracks = stream.getAudioTracks();
      if (audioTracks.length === 0) {
        setError("Aucun audio capturé. Coche 'Partager l'audio' et sélectionne l'onglet de ton appel.");
        return;
      }
      await startCapture(new MediaStream(audioTracks), "tab");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Tab audio capture denied");
    }
  }, [startCapture]);

  const stop = useCallback(() => {
    if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
    processorRef.current?.disconnect();
    audioCtxRef.current?.close();
    streamRef.current?.getTracks().forEach((t) => t.stop());
    processorRef.current = null;
    audioCtxRef.current = null;
    streamRef.current = null;
    setIsCapturing(false);
    setIsSpeaking(false);
    setAudioSource(null);
  }, []);

  useEffect(() => stop, [stop]);

  return { isCapturing, isSpeaking, audioSource, startMicrophone, startTabCapture, stop, error };
}

