export type InterviewLanguage = "fr" | "en" | "es" | "pt" | "zh";

export interface SessionConfig {
  language: InterviewLanguage;
}

export interface TechTranslation {
  term: string;
  definition: string;
  relatedTechs: string[];
  criticality: "HIGH" | "MEDIUM" | "LOW";
}

export interface TranscriptEntry {
  id: string;
  text: string;
  timestamp: number;
}

export type ClientMessage =
  | { type: "session:start"; config: SessionConfig }
  | { type: "session:stop" }
  | { type: "audio:chunk"; data: string }
  | { type: "ping" };

export type ServerMessage =
  | { type: "session:ready"; sessionId: string }
  | { type: "session:error"; error: string }
  | { type: "transcript:partial"; text: string }
  | { type: "transcript:final"; text: string }
  | { type: "tech:translation"; translation: TechTranslation }
  | { type: "assist:start" }
  | { type: "assist:chunk"; text: string }
  | { type: "assist:done"; fullText: string }
  | { type: "assist:error"; error: string }
  | { type: "pong" };

export const AUDIO_SAMPLE_RATE = 16000;
export const WS_PING_INTERVAL_MS = 30000;

export function createId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

import type { WebSocket } from "ws";
import type { ClientMessage, ServerMessage, SessionConfig, TechTranslation } from "@voxhelp/shared";
import { DeepgramSTT } from "./deepgram.js";
import { generateFromPrompt, callClaudeJSON } from "./llm.js";
import { buildLiveAssistPrompt } from "./prompts/live-assist.js";
import { buildTechTranslatePrompt } from "./prompts/tech-translate.js";

export class Session {
  private ws: WebSocket;
  private stt: DeepgramSTT | null = null;
  private config: SessionConfig | null = null;
  private transcriptBuffer: string[] = [];
  private debounceTimer: ReturnType<typeof setTimeout> | null = null;
  private isProcessing = false;
  private pendingTranscript: string | null = null;
  private readonly DEBOUNCE_MS = 1800;

  constructor(ws: WebSocket) {
    this.ws = ws;
    this.setupHandlers();
  }

  private setupHandlers(): void {
    this.ws.on("message", (data) => {
      try {
        const message: ClientMessage = JSON.parse(data.toString());
        this.handleMessage(message);
      } catch {
        if (Buffer.isBuffer(data) && this.stt) {
          this.stt.sendAudio(data);
        }
      }
    });

    this.ws.on("close", () => this.cleanup());
    this.ws.on("error", (err) => {
      console.error("[Session] WS error:", err.message);
      this.cleanup();
    });
  }

  private handleMessage(message: ClientMessage): void {
    switch (message.type) {
      case "session:start":
        this.startSession(message.config);
        break;
      case "session:stop":
        this.cleanup();
        break;
      case "audio:chunk":
        this.handleAudioChunk(message.data);
        break;
      case "ping":
        this.send({ type: "pong" });
        break;
    }
  }

  private startSession(config: SessionConfig): void {
    this.config = config;
    this.transcriptBuffer = [];

    this.stt = new DeepgramSTT(config.language, {
      onPartial: (text) => this.send({ type: "transcript:partial", text }),
      onFinal: (text) => this.handleFinalTranscript(text),
      onError: (err) => this.send({ type: "session:error", error: err }),
    });

    this.stt.connect();

    const sessionId = `session_${Date.now()}`;
    this.send({ type: "session:ready", sessionId });
    console.log(`[Session] Started: language=${config.language}`);
  }

  private handleAudioChunk(base64Data: string): void {
    if (!this.stt) return;
    const buffer = Buffer.from(base64Data, "base64");
    this.stt.sendAudio(buffer);
  }

  private handleFinalTranscript(text: string): void {
    if (!text.trim()) return;

    this.send({ type: "transcript:final", text });
    this.transcriptBuffer.push(text);

    if (this.debounceTimer) clearTimeout(this.debounceTimer);

    this.debounceTimer = setTimeout(() => {
      const fullText = this.transcriptBuffer.join(" ");
      this.transcriptBuffer = [];

      if (fullText.trim().length < 10) return;

      if (this.isProcessing) {
        this.pendingTranscript = fullText;
        return;
      }

      this.processTranscript(fullText);
    }, this.DEBOUNCE_MS);
  }

  private async processTranscript(transcript: string): Promise<void> {
    this.isProcessing = true;

    await Promise.all([
      this.runTechTranslation(transcript),
      this.runAssist(transcript),
    ]);

    this.isProcessing = false;

    if (this.pendingTranscript) {
      const pending = this.pendingTranscript;
      this.pendingTranscript = null;
      this.processTranscript(pending);
    }
  }

  private async runTechTranslation(transcript: string): Promise<void> {
    try {
      const result = await callClaudeJSON<{ translations: TechTranslation[] }>(
        buildTechTranslatePrompt(),
        `TRANSCRIPTION:\n"${transcript}"`
      );
      for (const translation of result.translations) {
        this.send({ type: "tech:translation", translation });
      }
    } catch (err) {
      console.error("[Session] Tech translation error:", err instanceof Error ? err.message : err);
    }
  }

  private async runAssist(transcript: string): Promise<void> {
    await generateFromPrompt(
      buildLiveAssistPrompt(),
      `Ce qui vient d'être dit :\n"${transcript}"`,
      {
        onStart: () => this.send({ type: "assist:start" }),
        onChunk: (text) => this.send({ type: "assist:chunk", text }),
        onDone: (fullText) => this.send({ type: "assist:done", fullText }),
        onError: (error) => this.send({ type: "assist:error", error }),
      }
    );
  }

  private send(message: ServerMessage): void {
    if (this.ws.readyState === this.ws.OPEN) {
      this.ws.send(JSON.stringify(message));
    }
  }

  private cleanup(): void {
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
    this.transcriptBuffer = [];
    if (this.stt) {
      this.stt.close();
      this.stt = null;
    }
    this.config = null;
    console.log("[Session] Cleaned up");
  }
}

import "dotenv/config";
import Fastify from "fastify";
import cors from "@fastify/cors";
import websocket from "@fastify/websocket";
import { Session } from "./session.js";

const PORT = Number(process.env.PORT) || 3001;
const CORS_ORIGIN = process.env.CORS_ORIGIN || "http://localhost:5173";

async function main() {
  const app = Fastify({ logger: true });

  await app.register(cors, { origin: CORS_ORIGIN });
  await app.register(websocket);

  app.get("/health", async () => ({ status: "ok", timestamp: Date.now() }));

  app.get("/ws", { websocket: true }, (socket) => {
    console.log("[Server] New WebSocket connection");
    new Session(socket);
  });

  try {
    await app.listen({ port: PORT, host: "0.0.0.0" });
    console.log(`\n🚀 VoxHelp backend on http://localhost:${PORT}`);
    console.log(`   WebSocket: ws://localhost:${PORT}/ws\n`);
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
}

main();

import { useCallback, useEffect, useRef, useState } from "react";
import type { ClientMessage, ServerMessage, SessionConfig, TranscriptEntry, TechTranslation } from "@voxhelp/shared";
import { createId, WS_PING_INTERVAL_MS } from "@voxhelp/shared";

type ConnectionStatus = "disconnected" | "connecting" | "connected" | "error";

interface AssistMessage {
  id: string;
  text: string;
  timestamp: number;
}

interface UseWebSocketReturn {
  status: ConnectionStatus;
  transcripts: TranscriptEntry[];
  currentPartial: string;
  techTranslations: TechTranslation[];
  currentAssist: { text: string; isStreaming: boolean } | null;
  assists: AssistMessage[];
  startSession: (config: SessionConfig) => void;
  stopSession: () => void;
  sendAudio: (base64: string) => void;
}

export function useWebSocket(url: string): UseWebSocketReturn {
  const wsRef = useRef<WebSocket | null>(null);
  const pingRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const [status, setStatus] = useState<ConnectionStatus>("disconnected");
  const [transcripts, setTranscripts] = useState<TranscriptEntry[]>([]);
  const [currentPartial, setCurrentPartial] = useState("");
  const [techTranslations, setTechTranslations] = useState<TechTranslation[]>([]);
  const [currentAssist, setCurrentAssist] = useState<{ text: string; isStreaming: boolean } | null>(null);
  const [assists, setAssists] = useState<AssistMessage[]>([]);

  const send = useCallback((msg: ClientMessage) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(msg));
    }
  }, []);

  const handleMessage = useCallback((msg: ServerMessage) => {
    switch (msg.type) {
      case "session:ready":
        break;
      case "session:error":
        console.error("[WS] Session error:", msg.error);
        break;
      case "transcript:partial":
        setCurrentPartial(msg.text);
        break;
      case "transcript:final":
        setCurrentPartial("");
        setTranscripts((prev) => [
          ...prev,
          { id: createId(), text: msg.text, timestamp: Date.now() },
        ]);
        break;
      case "tech:translation":
        setTechTranslations((prev) => [msg.translation, ...prev].slice(0, 5));
        break;
      case "assist:start":
        setCurrentAssist({ text: "", isStreaming: true });
        break;
      case "assist:chunk":
        setCurrentAssist((prev) =>
          prev ? { ...prev, text: prev.text + msg.text } : null
        );
        break;
      case "assist:done":
        setCurrentAssist(null);
        setAssists((prev) => [
          ...prev,
          { id: createId(), text: msg.fullText, timestamp: Date.now() },
        ]);
        break;
      case "assist:error":
        setCurrentAssist(null);
        console.error("[WS] Assist error:", msg.error);
        break;
      case "pong":
        break;
    }
  }, []);

  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) return;

    setStatus("connecting");
    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => {
      setStatus("connected");
      pingRef.current = setInterval(() => {
        send({ type: "ping" });
      }, WS_PING_INTERVAL_MS);
    };

    ws.onmessage = (event) => {
      try {
        const msg: ServerMessage = JSON.parse(event.data);
        handleMessage(msg);
      } catch {
        // ignore
      }
    };

    ws.onclose = () => {
      setStatus("disconnected");
      if (pingRef.current) {
        clearInterval(pingRef.current);
        pingRef.current = null;
      }
    };

    ws.onerror = () => setStatus("error");
  }, [url, send, handleMessage]);

  const startSession = useCallback(
    (config: SessionConfig) => {
      setTranscripts([]);
      setCurrentPartial("");
      setTechTranslations([]);
      setCurrentAssist(null);
      setAssists([]);

      if (wsRef.current?.readyState === WebSocket.OPEN) {
        send({ type: "session:start", config });
        return;
      }

      connect();
      const check = setInterval(() => {
        if (wsRef.current?.readyState === WebSocket.OPEN) {
          clearInterval(check);
          send({ type: "session:start", config });
        }
      }, 100);
    },
    [connect, send]
  );

  const stopSession = useCallback(() => {
    send({ type: "session:stop" });
  }, [send]);

  const sendAudio = useCallback(
    (base64: string) => {
      send({ type: "audio:chunk", data: base64 });
    },
    [send]
  );

  useEffect(() => {
    connect();
    return () => {
      if (pingRef.current) clearInterval(pingRef.current);
      wsRef.current?.close();
    };
  }, [connect]);

  return { status, transcripts, currentPartial, techTranslations, currentAssist, assists, startSession, stopSession, sendAudio };
}

import { useEffect, useRef, useState } from "react";
import type { TranscriptEntry, TechTranslation } from "@voxhelp/shared";
import { TechTranslationCard } from "./TechTranslationCard";

interface AssistMessage {
  id: string;
  text: string;
  timestamp: number;
}

interface LiveViewProps {
  transcripts: TranscriptEntry[];
  currentPartial: string;
  techTranslations: TechTranslation[];
  currentAssist: { text: string; isStreaming: boolean } | null;
  assists: AssistMessage[];
  wsStatus: string;
  isCapturing: boolean;
  isSpeaking: boolean;
  onStartAudio: () => Promise<void>;
  onStop: () => void;
}

function useElapsedTime(active: boolean) {
  const [elapsed, setElapsed] = useState(0);
  const startRef = useRef<number | null>(null);

  useEffect(() => {
    if (active) {
      startRef.current = Date.now();
      const id = setInterval(() => {
        setElapsed(Math.floor((Date.now() - (startRef.current ?? Date.now())) / 1000));
      }, 1000);
      return () => clearInterval(id);
    } else {
      setElapsed(0);
      startRef.current = null;
    }
  }, [active]);

  const mm = String(Math.floor(elapsed / 60)).padStart(2, "0");
  const ss = String(elapsed % 60).padStart(2, "0");
  return `${mm}:${ss}`;
}

export function LiveView({
  transcripts,
  currentPartial,
  techTranslations,
  currentAssist,
  assists,
  wsStatus,
  isCapturing,
  isSpeaking,
  onStartAudio,
  onStop,
}: LiveViewProps) {
  const transcriptEndRef = useRef<HTMLDivElement>(null);
  const assistEndRef = useRef<HTMLDivElement>(null);
  const [audioStarted, setAudioStarted] = useState(false);
  const elapsed = useElapsedTime(isCapturing);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [transcripts, currentPartial]);

  useEffect(() => {
    assistEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [assists, currentAssist, techTranslations]);

  const handleStart = async () => {
    await onStartAudio();
    setAudioStarted(true);
  };

  return (
    <div className="h-screen bg-[#F6F7FB] flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-[#DFE1EA] px-6 py-3 flex items-center justify-between flex-shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-7 h-7 rounded-lg bg-[#3D5AFE] flex items-center justify-center">
            <span className="text-white text-[10px] font-bold">VH</span>
          </div>
          <span className="font-semibold text-[#1A1D26] text-sm">VoxHelp</span>
        </div>
        <div className={`flex items-center gap-1.5 text-xs ${wsStatus === "connected" ? "text-[#0FAA6C]" : "text-[#5A5F72]"}`}>
          <div className={`w-2 h-2 rounded-full ${wsStatus === "connected" ? "bg-[#0FAA6C]" : "bg-gray-300"}`} />
          {wsStatus === "connected" ? "Connecté" : wsStatus}
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Left: Transcript */}
        <div className="flex-1 flex flex-col border-r border-[#DFE1EA] overflow-hidden">
          <div className="px-4 py-2 bg-white border-b border-[#DFE1EA] flex items-center justify-between flex-shrink-0">
            <span className="text-xs font-semibold uppercase tracking-wider text-[#5A5F72]">Transcription</span>
            {!audioStarted ? (
              <button
                onClick={handleStart}
                className="text-xs bg-[#3D5AFE] text-white px-3 py-1 rounded-lg hover:bg-[#3451e0] transition-colors"
              >
                Démarrer l'écoute
              </button>
            ) : (
              <div className="flex items-center gap-1.5 text-xs">
                <div className={`w-2 h-2 rounded-full ${isSpeaking ? "bg-[#3D5AFE] animate-pulse" : "bg-[#0FAA6C]"}`} />
                <span className={isSpeaking ? "text-[#3D5AFE]" : "text-[#0FAA6C]"}>
                  {isSpeaking ? "Parole détectée" : "En écoute"}
                </span>
              </div>
            )}
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {transcripts.length === 0 && !currentPartial && (
              <div className="flex items-center justify-center h-full text-center text-[#5A5F72]">
                <div>
                  <div className="text-4xl mb-3">🎤</div>
                  <p className="text-sm">
                    {audioStarted ? "En écoute..." : "Démarrez l'écoute pour commencer"}
                  </p>
                </div>
              </div>
            )}
            {transcripts.map((entry) => (
              <div key={entry.id} className="flex gap-3">
                <div className="w-7 h-7 rounded-full bg-[#F6F7FB] border border-[#DFE1EA] flex items-center justify-center text-xs flex-shrink-0 mt-0.5">
                  🎤
                </div>
                <div className="bg-white border border-[#DFE1EA] rounded-xl px-4 py-2.5 text-sm text-[#1A1D26] shadow-sm max-w-[85%]">
                  {entry.text}
                </div>
              </div>
            ))}
            {currentPartial && (
              <div className="flex gap-3">
                <div className="w-7 h-7 rounded-full bg-[#F6F7FB] border border-[#DFE1EA] flex items-center justify-center text-xs flex-shrink-0 mt-0.5">
                  🎤
                </div>
                <div className="bg-white border border-[#DFE1EA] rounded-xl px-4 py-2.5 text-sm text-[#5A5F72] italic opacity-70 shadow-sm max-w-[85%]">
                  {currentPartial}...
                </div>
              </div>
            )}
            <div ref={transcriptEndRef} />
          </div>
        </div>

        {/* Right: Explanations */}
        <div className="w-80 flex flex-col overflow-hidden bg-white">
          <div className="px-4 py-2 border-b border-[#DFE1EA] flex-shrink-0">
            <span className="text-xs font-semibold uppercase tracking-wider text-[#5A5F72]">Explications IA</span>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {techTranslations.length === 0 && assists.length === 0 && !currentAssist && (
              <div className="text-xs text-[#5A5F72] text-center pt-8">
                Les explications des termes techniques apparaîtront ici
              </div>
            )}

            {techTranslations.map((t, i) => (
              <TechTranslationCard key={`${t.term}-${i}`} translation={t} />
            ))}

            {assists.slice(-5).map((a) => (
              <div key={a.id} className="bg-[#F6F7FB] border border-[#DFE1EA] rounded-xl p-3">
                <p className="text-[10px] font-semibold uppercase tracking-wider text-[#3D5AFE] mb-1.5">Analyse</p>
                <p className="text-xs text-[#1A1D26] leading-relaxed whitespace-pre-wrap">{a.text}</p>
              </div>
            ))}

            {currentAssist && (
              <div className="bg-[#F6F7FB] border border-[#3D5AFE]/30 rounded-xl p-3">
                <p className="text-[10px] font-semibold uppercase tracking-wider text-[#3D5AFE] mb-1.5">Analyse</p>
                <p className="text-xs text-[#1A1D26] leading-relaxed whitespace-pre-wrap cursor-blink">
                  {currentAssist.text}
                </p>
              </div>
            )}

            <div ref={assistEndRef} />
          </div>
        </div>
      </div>

      {/* Bottom bar */}
      <div className="bg-white border-t border-[#DFE1EA] px-6 py-3 flex items-center justify-between flex-shrink-0">
        <div className="flex items-center gap-2 text-sm">
          {isCapturing && <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />}
          <span className="text-[#1A1D26] font-medium">
            {isCapturing ? `En cours · ${elapsed}` : "En attente"}
          </span>
        </div>
        <button
          onClick={onStop}
          className="bg-red-500 text-white px-5 py-2 rounded-xl text-sm font-semibold hover:bg-red-600 transition-colors"
        >
          ⏹ Arrêter
        </button>
      </div>
    </div>
  );
}

import { useWebSocket } from "./hooks/useWebSocket";
import { useAudioCapture } from "./hooks/useAudioCapture";
import { LiveView } from "./components/LiveView";

const WS_URL = `ws://${window.location.hostname}:3001/ws`;

export default function App() {
  const ws = useWebSocket(WS_URL);
  const audio = useAudioCapture(ws.sendAudio);

  const handleStartAudio = async () => {
    ws.startSession({ language: "fr" });
    try {
      await audio.startTabCapture();
    } catch {
      await audio.startMicrophone();
    }
  };

  const handleStop = () => {
    ws.stopSession();
    audio.stop();
  };

  return (
    <LiveView
      transcripts={ws.transcripts}
      currentPartial={ws.currentPartial}
      techTranslations={ws.techTranslations}
      currentAssist={ws.currentAssist}
      assists={ws.assists}
      wsStatus={ws.status}
      isCapturing={audio.isCapturing}
      isSpeaking={audio.isSpeaking}
      onStartAudio={handleStartAudio}
      onStop={handleStop}
    />
  );
}
